-- ============================================================
-- BIOSYNC COMPREHENSIVE SCHEMA - Missing Tables
-- This file contains SQL definitions for tables referenced
-- in the codebase but not yet defined in the schema files.
-- Run this in Supabase SQL Editor after the base schemas.
-- ============================================================

-- ============================================================
-- 0. AI-GENERATED MISSIONS (weekly + daily, generated by DeepSeek AI)
-- ============================================================

-- Weekly missions: AI generates 5 personalized missions every Monday
-- based on user level, league tier, and recent activity history.
CREATE TABLE IF NOT EXISTS weekly_missions (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
    title VARCHAR(255) NOT NULL,
    title_tr VARCHAR(255),
    description TEXT,
    description_tr TEXT,
    category VARCHAR(50) NOT NULL DEFAULT 'workout', -- workout, nutrition, health, social, streak
    target_value INTEGER NOT NULL DEFAULT 1,
    current_progress INTEGER NOT NULL DEFAULT 0,
    xp_reward INTEGER NOT NULL DEFAULT 100,
    point_reward INTEGER NOT NULL DEFAULT 50,
    is_completed BOOLEAN DEFAULT false,
    week_start DATE NOT NULL,
    week_end DATE NOT NULL,
    completed_at TIMESTAMPTZ,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- Daily missions: AI generates 3 quick missions each day
CREATE TABLE IF NOT EXISTS daily_missions (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
    title VARCHAR(255) NOT NULL,
    title_tr VARCHAR(255),
    description TEXT,
    description_tr TEXT,
    category VARCHAR(50) NOT NULL DEFAULT 'workout', -- workout, nutrition, health
    target_value INTEGER NOT NULL DEFAULT 1,
    current_progress INTEGER NOT NULL DEFAULT 0,
    xp_reward INTEGER NOT NULL DEFAULT 20,
    point_reward INTEGER NOT NULL DEFAULT 10,
    is_completed BOOLEAN DEFAULT false,
    mission_date DATE NOT NULL DEFAULT CURRENT_DATE,
    completed_at TIMESTAMPTZ,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE weekly_missions ENABLE ROW LEVEL SECURITY;
ALTER TABLE daily_missions ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users manage own weekly_missions" ON weekly_missions FOR ALL USING (auth.uid() = user_id);
CREATE POLICY "Users manage own daily_missions" ON daily_missions FOR ALL USING (auth.uid() = user_id);

CREATE INDEX IF NOT EXISTS idx_weekly_missions_user_week ON weekly_missions(user_id, week_start, week_end);
CREATE INDEX IF NOT EXISTS idx_daily_missions_user_date ON daily_missions(user_id, mission_date);

-- ============================================================
-- 1. CORE DATA TABLES (used by supabase.ts)
-- ============================================================

CREATE TABLE IF NOT EXISTS exercises (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    name VARCHAR(255) NOT NULL,
    name_tr VARCHAR(255),
    description TEXT,
    description_tr TEXT,
    muscle_group VARCHAR(100),
    secondary_muscles TEXT[],
    equipment VARCHAR(100),
    difficulty VARCHAR(20) DEFAULT 'intermediate', -- beginner, intermediate, advanced
    instructions TEXT[],
    tips TEXT[],
    calories_per_rep NUMERIC(5,2) DEFAULT 0,
    image_url TEXT,
    video_url TEXT,
    is_active BOOLEAN DEFAULT true,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS food_items (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    name VARCHAR(255) NOT NULL,
    name_tr VARCHAR(255),
    category VARCHAR(100),
    calories NUMERIC(8,2) DEFAULT 0,
    protein NUMERIC(8,2) DEFAULT 0,
    carbs NUMERIC(8,2) DEFAULT 0,
    fat NUMERIC(8,2) DEFAULT 0,
    fiber NUMERIC(8,2) DEFAULT 0,
    serving_size VARCHAR(100),
    serving_unit VARCHAR(50),
    barcode VARCHAR(100),
    image_url TEXT,
    is_active BOOLEAN DEFAULT true,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS food_scans (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
    food_item_id UUID REFERENCES food_items(id),
    scan_type VARCHAR(50) DEFAULT 'photo', -- photo, barcode
    image_url TEXT,
    ai_result JSONB,
    calories NUMERIC(8,2),
    protein NUMERIC(8,2),
    carbs NUMERIC(8,2),
    fat NUMERIC(8,2),
    created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS health_records (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
    record_type VARCHAR(50) NOT NULL, -- steps, heart_rate, sleep, blood_pressure
    value NUMERIC(10,2),
    unit VARCHAR(30),
    metadata JSONB,
    recorded_at TIMESTAMPTZ DEFAULT NOW(),
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- ============================================================
-- 2. WATER TRACKING (to enable Supabase sync)
-- ============================================================

CREATE TABLE IF NOT EXISTS water_logs (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
    date DATE NOT NULL DEFAULT CURRENT_DATE,
    amount_ml INTEGER NOT NULL DEFAULT 0,
