-- ============================================================
-- 14. CONTENT MODERATION & SAFETY
-- Columns and tables needed for NSFW detection, bans, and reporting
-- ============================================================

-- Add moderation columns to profiles
ALTER TABLE profiles ADD COLUMN IF NOT EXISTS avatar_url TEXT;
ALTER TABLE profiles ADD COLUMN IF NOT EXISTS is_banned BOOLEAN DEFAULT false;
ALTER TABLE profiles ADD COLUMN IF NOT EXISTS ban_reason TEXT;
ALTER TABLE profiles ADD COLUMN IF NOT EXISTS ban_expires_at TIMESTAMPTZ;
ALTER TABLE profiles ADD COLUMN IF NOT EXISTS content_violation_count INTEGER DEFAULT 0;

-- Content violations log
CREATE TABLE IF NOT EXISTS content_violations (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
    violation_type VARCHAR(100) NOT NULL, -- nsfw_profile_photo, inappropriate_message, etc.
    details TEXT,
    action_taken VARCHAR(50), -- warning, temp_ban, permanent_ban
    created_at TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE content_violations ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Only admins can view content violations"
ON content_violations FOR SELECT
USING (
    EXISTS (
        SELECT 1 FROM profiles WHERE id = auth.uid() AND role = 'admin'
    )
    OR auth.uid() = user_id
);
CREATE POLICY "System can insert violations"
ON content_violations FOR INSERT
WITH CHECK (auth.uid() = user_id);

-- Content reports (user-to-user reporting)
CREATE TABLE IF NOT EXISTS content_reports (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    reported_by UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
    reported_user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
    content_type VARCHAR(50) NOT NULL, -- profile_photo, message, forum_post, comment
    content_id TEXT, -- ID of the reported content
    reason TEXT NOT NULL,
    status VARCHAR(30) DEFAULT 'pending' CHECK (status IN ('pending', 'reviewed', 'resolved', 'dismissed')),
    reviewed_by UUID REFERENCES profiles(id),
    reviewed_at TIMESTAMPTZ,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE content_reports ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Users can report content"
ON content_reports FOR INSERT
WITH CHECK (auth.uid() = reported_by);
CREATE POLICY "Users can view own reports"
ON content_reports FOR SELECT
USING (auth.uid() = reported_by OR EXISTS (SELECT 1 FROM profiles WHERE id = auth.uid() AND role = 'admin'));

-- Indexes for moderation tables
CREATE INDEX IF NOT EXISTS idx_content_violations_user ON content_violations(user_id);
CREATE INDEX IF NOT EXISTS idx_content_reports_status ON content_reports(status);
CREATE INDEX IF NOT EXISTS idx_content_reports_reported_user ON content_reports(reported_user_id);
CREATE INDEX IF NOT EXISTS idx_profiles_is_banned ON profiles(is_banned) WHERE is_banned = true;
